export const getMatchpointRankingAuditDashboard = onCall(
  { region: "southamerica-east1", memory: "256MiB", invoker: "public" },
  async (request) => {
    assertAdmin(request);

    const requestedLimit = Number(request.data?.limit ?? 24);
